from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
from eth_utils import is_address, to_checksum_address
import os
import secrets
import time

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
nonces = {}

def now_ts():
    return int(time.time())

def cleanup_nonces():
    current = now_ts()
    expired = [addr for addr, data in nonces.items() if data["expires_at"] < current]
    for addr in expired:
        nonces.pop(addr, None)

def issue_nonce(address):
    cleanup_nonces()
    checksum = to_checksum_address(address)
    nonce = secrets.token_urlsafe(24)
    nonces[checksum] = {
        "nonce": nonce,
        "issued_at": now_ts(),
        "expires_at": now_ts() + NONCE_TTL_SECONDS,
        "used": False,
    }
    return nonce

def get_sign_message(address, nonce):
    return f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {nonce}"

@app.get("/health")
def health():
    return jsonify({"status": "ok"})

@app.post("/auth/nonce")
def auth_nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    if not address or not isinstance(address, str) or not is_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    checksum = to_checksum_address(address)
    nonce = issue_nonce(checksum)
    message = get_sign_message(checksum, nonce)

    return jsonify({
        "address": checksum,
        "nonce": nonce,
        "message": message,
        "expires_in": NONCE_TTL_SECONDS
    })

@app.post("/auth/verify")
def auth_verify():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    signature = data.get("signature")
    message = data.get("message")

    if not address or not isinstance(address, str) or not is_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    if not signature or not isinstance(signature, str):
        return jsonify({"error": "Missing or invalid signature"}), 400

    checksum = to_checksum_address(address)
    nonce_record = nonces.get(checksum)

    if not nonce_record:
        return jsonify({"error": "No active nonce for address"}), 400

    if nonce_record["used"]:
        return jsonify({"error": "Nonce already used"}), 400

    if nonce_record["expires_at"] < now_ts():
        nonces.pop(checksum, None)
        return jsonify({"error": "Nonce expired"}), 400

    expected_message = get_sign_message(checksum, nonce_record["nonce"])

    if message is not None and message != expected_message:
        return jsonify({"error": "Message does not match expected authentication payload"}), 400

    try:
        encoded_message = encode_defunct(text=expected_message)
        recovered = w3.eth.account.recover_message(encoded_message, signature=signature)
    except Exception as e:
        return jsonify({"error": "Signature verification failed", "details": str(e)}), 400

    recovered_checksum = to_checksum_address(recovered)

    if recovered_checksum != checksum:
        return jsonify({
            "authenticated": False,
            "error": "Recovered address does not match claimed address",
            "recovered_address": recovered_checksum
        }), 401

    nonce_record["used"] = True

    return jsonify({
        "authenticated": True,
        "address": checksum,
        "recovered_address": recovered_checksum
    })

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8000"))
    debug = os.getenv("DEBUG", "false").lower() == "true"
    app.run(host=host, port=port, debug=debug)